/**
 * @typedef jibo.system#OneAxisState
 * @description The state of one particular axis.
 * @prop ts {number[]} Chronometer timestamp.
 * @prop pos {number} Absolute (Indexed) position in radians, wraps at +- PI on the axis, undefined until indexed.
 * @prop inc_pos {number} Arbitrary power-up position in ticks; wraps at `2^32`.
 * @prop vel {number} Velocity in radians/second.
 * @prop cur {number} Current in amperes.
 * @prop pwm {number} PWM value in % max PWM.
 * @prop status {jibo.system#StatusFlags} Low level flags for motor and driver status (number).
 * @prop vel_limit {number} Velocity limit in radians/second for trajectory limiting.
 * @prop acc_limit {number} Acceleration limit in radians/second^2 for trajectory limiting.
 * @prop cur_limit {number} Current limit in amperes for torque/power limiting.
 * @prop mode {number} Command mode of the axis in {`none=0`; `limp=1`; `brake=2`; `pwm=3`; `vel=4`; `traj=5`; `trq=6`; `pos_vel=7`}
 * @prop ref {number} Reference value of trajectory generator (depends on command).
 * @prop ref_pos {number} Reference position of trajectory generator (depends on command).
 * @prop ref_acc {number} Reference acceleration of trajectory generator (depends on command).
 * @prop ticks {number} Hardware level tick counter for each axis (milliseconds).
 * @prop integrator {number} Value of the integral term of the PID loop.
 * @prop fault_status {jibo.system#FaultFlags} Low level motor fault flags.
 * @prop index_count {number} Counter of the number of observed index events. Intended for skills to reindex the axis. Wraps after `255`.
 * @prop limiter_mode {number} Motion limiter operation mode (`-1 == DISABLED`, `0 == OK`, `1 == APPROACHING_LIMIT`, `2 == EXCEEDING_LIMIT`).
 */

/**
 * @typedef jibo.system#AxisState
 * @description All attributes of incoming sectors from LPS Service.
 * @prop {number[]} ts Timestamp in [seconds, microseconds] of event.
 * @prop {jibo.system#OneAxisState} pelvis The Pelvis axis state
 * @prop {jibo.system#OneAxisState} torso The Torso axis state
 * @prop {jibo.system#OneAxisState} neck The Neck axis state
 * @prop {jibo.system#LockoutFlags} lockout Bitmask representing lockout conditions, e.g. system policies that prevent control of the motors
 */

/**
 * @typedef jibo.system#StatusFlags
 * @description Enum of axis statuses.
 * @prop INDEXED The axis has been indexed. Position data can be trusted.
 * @prop ENABLED The axis is being commanded.
 * @prop BRAKED The axis is prevented from moving.
 * @prop MOVING The axis is moving.
 * @prop STALLED The axis is unable to drive.
 * @prop TIMEOUT The most recent axis command has expired.
 * @prop FAULT There is an axis fault.
 */

/**
 * @typedef jibo.system#FaultFlags
 * @description Enum of possible fault statuses.
 * @prop INDEXED The robot is not indexed.
 * @prop POWER Motor is not receiving power.
 * @prop STALL Motion is being prevented by an outside force.
 * @prop ENCODER The encoder value is unreadable.
 * @prop ENCODER_BACKWARDS The encoder count is running backwards.
 * @prop THERMISTOR The thermistor value is out of range.
 */

/**
 * @typedef jibo.system#LockoutFlags
 * @description Enum of possible lockout scenarios.
 * @prop NO_BATTERY Battery is not installed or nonfunctional.
 * @prop NOT_UPRIGHT Orientation is out of bounds.
 * @prop FALLING Acceleration is out of bounds.
 */

/**
 * Enum of the different messages for power sources.
 * @typedef jibo.system#PowerSource
 * @property BATTERY {String} 'BATTERY'
 * @property EXTERNAL {String} 'EXTERNAL'
 */